<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Estimates</h1><p class="text-muted mb-0">Build, send, and convert estimates.</p></div><a class="btn btn-primary" href="/portal/estimates/create"><i class="fa-solid fa-plus"></i> New Estimate</a></div>
<div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Estimate</th><th>Customer</th><th>Status</th><th>Valid until</th><th>Total</th><th></th></tr></thead><tbody><?php foreach($estimates as $r):?><tr><td><strong><?=e($r['estimate_number'])?></strong></td><td><?=e($r['display_name'])?></td><td><span class="badge text-bg-<?=in_array($r['status'],['accepted'],true)?'success':($r['status']==='sent'?'primary':'secondary')?>"><?=e($r['status'])?></span></td><td><?=e($r['valid_until'])?></td><td><?=money($r['total'])?></td><td class="text-end"><a class="btn btn-sm btn-outline-primary" href="/portal/estimates/<?=$r['id']?>">Open</a></td></tr><?php endforeach; if(!$estimates):?><tr><td colspan="6" class="text-center py-5 text-muted">No estimates yet.</td></tr><?php endif?></tbody></table></div></div>
